Value::Value(TypeId type, double d) : Value(type) {
  switch (type) {
    case TypeId::DECIMAL: value_.decimal_ = d; size_.len_ = (value_.decimal_ == BUSTUB_DECIMAL_NULL ? BUSTUB_VALUE_NULL : 0); break;
    default: throw Exception(ExceptionType::INCOMPATIBLE_TYPE, "Invalid Type for double Value constructor");
  }
}

Value::Value(TypeId type, float f) : Value(type) {
  switch (type) {
    case TypeId::DECIMAL: value_.decimal_ = f; size_.len_ = (value_.decimal_ == BUSTUB_DECIMAL_NULL ? BUSTUB_VALUE_NULL : 0); break;
    default: throw Exception(ExceptionType::INCOMPATIBLE_TYPE, "Invalid Type for float value constructor");
  }
}

Value::Value(TypeId type, const char *data, uint32_t len, bool manage_data) : Value(type) {
  switch (type) {
    case TypeId::VARCHAR:
    case TypeId::VECTOR:
      if (data == nullptr) {
        value_.varlen_ = nullptr;
        size_.len_ = BUSTUB_VALUE_NULL;
      } else {
        manage_data_ = manage_data;
        if (manage_data_) {
          assert(len < BUSTUB_VARCHAR_MAX_LEN);
          value_.varlen_ = new char[len];
          assert(value_.varlen_ != nullptr);
          size_.len_ = len;
          memcpy(value_.varlen_, data, len);
        } else {
          value_.const_varlen_ = data;
          size_.len_ = len;
        }
      }
      break;
    default:
      throw Exception(ExceptionType::INCOMPATIBLE_TYPE, "Invalid Type for variable-length Value constructor");
  }
}

Value::Value(TypeId type, const std::string &data) : Value(type) {
  switch (type) {
    case TypeId::VARCHAR: {
      manage_data_ = true;
      uint32_t len = static_cast<uint32_t>(data.length()) + 1;
      value_.varlen_ = new char[len];
      assert(value_.varlen_ != nullptr);
      size_.len_ = len;
      memcpy(value_.varlen_, data.c_str(), len);
      break;
    }
    default:
      throw Exception(ExceptionType::INCOMPATIBLE_TYPE, "Invalid Type for variable-length Value constructor");
  }
}

Value::Value(TypeId type, const std::vector<double> &data) : Value(type) {
  switch (type) {
    case TypeId::VECTOR: {
      manage_data_ = true;
      auto len = data.size() * sizeof(double);
      value_.varlen_ = new char[len];
      assert(value_.varlen_ != nullptr);
      size_.len_ = len;
      memcpy(value_.varlen_, data.data(), len);
      break;
    }
    default:
      throw Exception(ExceptionType::INCOMPATIBLE_TYPE, "Invalid Type for vector Value constructor");
  }
}

Value::~Value() {
  switch (type_id_) {
    case TypeId::VARCHAR:
    case TypeId::VECTOR:
      if (manage_data_) { delete[] value_.varlen_; }
      break;
    default:
      break;
  }
}

