#include "primer/hyperloglog_presto.h"

#include <algorithm>
#include <cmath>

namespace bustub {

template <typename KeyType>
HyperLogLogPresto<KeyType>::HyperLogLogPresto(int16_t n_leading_bits)
    : cardinality_(0), n_bits_(n_leading_bits) {
  if (n_bits_ < 0) {
    m_ = 0;
    // dense_bucket_ stays empty
  } else {
    m_ = static_cast<int64_t>(1) << n_bits_;
    dense_bucket_.resize(m_);  // bitset<4> default-initialized to 0
  }
}

template <typename KeyType>
auto HyperLogLogPresto<KeyType>::AddElem(KeyType val) -> void {
  if (n_bits_ < 0 || m_ == 0) return;

  hash_t hash = CalculateHash(val);

  // Determine register index and value bits
  uint64_t j = 0;
  uint64_t value_bits = hash;
  if (n_bits_ > 0) {
    j = hash >> (static_cast<uint64_t>(64) - static_cast<uint64_t>(n_bits_));
    // Value bits: bottom (64 - n_bits_) bits
    uint64_t mask = (static_cast<uint64_t>(1) << (64 - n_bits_)) - 1;
    value_bits = hash & mask;
  }
  // For n_bits_==0: j=0, value_bits=hash

  // Count trailing zeros; for all-zero: cap at (64 - n_bits_)
  uint64_t trailing_zeros;
  if (value_bits == 0) {
    trailing_zeros = static_cast<uint64_t>(64 - n_bits_);
  } else {
    trailing_zeros = static_cast<uint64_t>(__builtin_ctzll(value_bits));
  }

  // Get current register value from dense + overflow buckets
  uint64_t current_val =
      static_cast<uint64_t>(dense_bucket_[j].to_ulong()) |
      (static_cast<uint64_t>(overflow_bucket_[j].to_ulong()) << DENSE_BUCKET_SIZE);

  // Update if new value is greater
  if (trailing_zeros > current_val) {
    dense_bucket_[j] = std::bitset<DENSE_BUCKET_SIZE>(trailing_zeros & 0xF);
    overflow_bucket_[j] = std::bitset<OVERFLOW_BUCKET_SIZE>(trailing_zeros >> DENSE_BUCKET_SIZE);
  }
}

template <typename KeyType>
auto HyperLogLogPresto<KeyType>::ComputeCardinality() -> void {
  if (n_bits_ < 0 || m_ == 0) {
    cardinality_ = 0;
    return;
  }

  // E = CONSTANT * m^2 / sum(2^{-M[j]})
  double sum = 0.0;
  for (int64_t j = 0; j < m_; j++) {
    uint64_t reg_val =
        static_cast<uint64_t>(dense_bucket_[j].to_ulong()) |
        (static_cast<uint64_t>(overflow_bucket_[j].to_ulong()) << DENSE_BUCKET_SIZE);
    sum += std::pow(2.0, -static_cast<double>(reg_val));
  }

  double estimate = CONSTANT * static_cast<double>(m_) * static_cast<double>(m_) / sum;
  cardinality_ = static_cast<uint64_t>(std::floor(estimate));
}

