20: namespace bustub {
21: #define VARLEN_COMPARE_FUNC(OP)                                               \
22:   const char *str1 = left.GetData();                                          \
23:   uint32_t len1 = GetStorageSize(left) - 1;                                   \
24:   const char *str2;                                                           \
25:   uint32_t len2;                                                              \
26:   if (right.GetTypeId() == TypeId::VARCHAR) {                                 \
27:     str2 = right.GetData();                                                   \
28:     len2 = GetStorageSize(right) - 1;                                         \
29:     /* NOLINTNEXTLINE */                                                      \
30:     return GetCmpBool(TypeUtil::CompareStrings(str1, len1, str2, len2) OP 0); \
31:   } else {                                                                    \
32:     auto r_value = right.CastAs(TypeId::VARCHAR);                             \
33:     str2 = r_value.GetData();                                                 \
34:     len2 = GetStorageSize(r_value) - 1;                                       \
35:     /* NOLINTNEXTLINE */                                                      \
36:     return GetCmpBool(TypeUtil::CompareStrings(str1, len1, str2, len2) OP 0); \
37:   }
38: 
39: VarlenType::VarlenType(TypeId type) : Type(type) {}
40: 
41: VarlenType::~VarlenType() = default;
42: 
43: // Access the raw variable length data
44: auto VarlenType::GetData(const Value &val) const -> const char * { return val.value_.varlen_; }
45: 
46: // Get the length of the variable length data (including the length field)
47: auto VarlenType::GetStorageSize(const Value &val) const -> uint32_t { return val.size_.len_; }
48: 
49: auto VarlenType::CompareEquals(const Value &left, const Value &right) const -> CmpBool {
50:   assert(left.CheckComparable(right));
51:   if (left.IsNull() || right.IsNull()) {
52:     return CmpBool::CmpNull;
53:   }
54: 
55:   VARLEN_COMPARE_FUNC(==);  // NOLINT
56: }
57: 
58: auto VarlenType::CompareNotEquals(const Value &left, const Value &right) const -> CmpBool {
59:   assert(left.CheckComparable(right));
60:   if (left.IsNull() || right.IsNull()) {
61:     return CmpBool::CmpNull;
62:   }
63: 
64:   VARLEN_COMPARE_FUNC(!=);  // NOLINT
65: }
66: 
67: auto VarlenType::CompareLessThan(const Value &left, const Value &right) const -> CmpBool {
68:   assert(left.CheckComparable(right));
69:   if (left.IsNull() || right.IsNull()) {
70:     return CmpBool::CmpNull;
71:   }
72: 
73:   VARLEN_COMPARE_FUNC(<);  // NOLINT
74: }
75: 
76: auto VarlenType::CompareLessThanEquals(const Value &left, const Value &right) const -> CmpBool {
77:   assert(left.CheckComparable(right));
78:   if (left.IsNull() || right.IsNull()) {
79:     return CmpBool::CmpNull;
80:   }
81: 
82:   VARLEN_COMPARE_FUNC(<=);  // NOLINT
83: }
84: 
85: auto VarlenType::CompareGreaterThan(const Value &left, const Value &right) const -> CmpBool {
86:   assert(left.CheckComparable(right));
87:   if (left.IsNull() || right.IsNull()) {
88:     return CmpBool::CmpNull;
89:   }
90: 
91:   VARLEN_COMPARE_FUNC(>);  // NOLINT
92: }
93: 
94: auto VarlenType::CompareGreaterThanEquals(const Value &left, const Value &right) const -> CmpBool {
95:   assert(left.CheckComparable(right));
96:   if (left.IsNull() || right.IsNull()) {
97:     return CmpBool::CmpNull;
98:   }
99: 
100:   VARLEN_COMPARE_FUNC(>=);  // NOLINT
101: }
102: 
103: auto VarlenType::Min(const Value &left, const Value &right) const -> Value {
104:   assert(left.CheckComparable(right));
105:   if (left.IsNull() || right.IsNull()) {
106:     return left.OperateNull(right);
107:   }
108:   if (left.CompareLessThan(right) == CmpBool::CmpTrue) {
109:     return left.Copy();
110:   }
111:   return right.Copy();
112: }
113: 
114: auto VarlenType::Max(const Value &left, const Value &right) const -> Value {
115:   assert(left.CheckComparable(right));
116:   if (left.IsNull() || right.IsNull()) {
117:     return left.OperateNull(right);
118:   }
119:   if (left.CompareGreaterThan(right) == CmpBool::CmpTrue) {
120:     return left.Copy();
121:   }
122:   return right.Copy();
123: }
124: 
125: auto VarlenType::ToString(const Value &val) const -> std::string {
126:   uint32_t len = GetStorageSize(val);
127: 
128:   if (val.IsNull()) {
129:     return "varlen_null";
130:   }
131:   if (len == BUSTUB_VARCHAR_MAX_LEN) {
132:     return "varlen_max";
133:   }
134:   if (len == 0) {
135:     return "";
136:   }
137:   return {GetData(val), len - 1};
138: }
139: 
140: void VarlenType::SerializeTo(const Value &val, char *storage) const {
141:   uint32_t len = GetStorageSize(val);
142:   if (len == BUSTUB_VALUE_NULL) {
143:     memcpy(storage, &len, sizeof(uint32_t));
144:     return;
145:   }
146:   memcpy(storage, &len, sizeof(uint32_t));
147:   memcpy(storage + sizeof(uint32_t), val.value_.varlen_, len);
148: }
149: 
150: // Deserialize a value of the given type from the given storage space.
151: auto VarlenType::DeserializeFrom(const char *storage) const -> Value {
152:   uint32_t len = *reinterpret_cast<const uint32_t *>(storage);
153:   if (len == BUSTUB_VALUE_NULL) {
154:     return {type_id_, nullptr, len, false};
155:   }
156:   // set manage_data as true
157:   return {type_id_, storage + sizeof(uint32_t), len, true};
158: }
159: 
160: auto VarlenType::Copy(const Value &val) const -> Value { return {val}; }
161: 
162: auto VarlenType::CastAs(const Value &value, const TypeId type_id) const -> Value {
163:   std::string str;
164:   // switch begins
165:   switch (type_id) {
166:     case TypeId::BOOLEAN: {
167:       str = value.ToString();
168:       std::transform(str.begin(), str.end(), str.begin(), ::tolower);
169:       if (str == "true" || str == "1" || str == "t") {
170:         return {type_id, 1};
171:       }
172:       if (str == "false" || str == "0" || str == "f") {
173:         return {type_id, 0};
174:       }
175:       throw Exception("Boolean value format error.");
176:     }
177:     case TypeId::TINYINT: {
178:       str = value.ToString();
179:       int8_t tinyint = 0;
180:       try {
181:         tinyint = static_cast<int8_t>(stoi(str));
182:       } catch (std::out_of_range &e) {
183:         throw Exception(ExceptionType::OUT_OF_RANGE, "Numeric value out of range.");
184:       }
185:       if (tinyint < BUSTUB_INT8_MIN) {
186:         throw Exception(ExceptionType::OUT_OF_RANGE, "Numeric value out of range.");
187:       }
188:       return {type_id, tinyint};
189:     }
190:     case TypeId::SMALLINT: {
191:       str = value.ToString();
192:       int16_t smallint = 0;
193:       try {
194:         smallint = static_cast<int16_t>(stoi(str));
195:       } catch (std::out_of_range &e) {
196:         throw Exception(ExceptionType::OUT_OF_RANGE, "Numeric value out of range.");
197:       }
198:       if (smallint < BUSTUB_INT16_MIN) {
199:         throw Exception(ExceptionType::OUT_OF_RANGE, "Numeric value out of range.");
200:       }
201:       return {type_id, smallint};
202:     }
203:     case TypeId::INTEGER: {
204:       str = value.ToString();
205:       int32_t integer = 0;
206:       try {
207:         integer = stoi(str);
208:       } catch (std::out_of_range &e) {
209:         throw Exception(ExceptionType::OUT_OF_RANGE, "Numeric value out of range.");
210:       }
211:       if (integer > BUSTUB_INT32_MAX || integer < BUSTUB_INT32_MIN) {
212:         throw Exception(ExceptionType::OUT_OF_RANGE, "Numeric value out of range.");
213:       }
214:       return {type_id, integer};
215:     }
216:     case TypeId::BIGINT: {
217:       str = value.ToString();
218:       int64_t bigint = 0;
219:       try {
220:         bigint = stoll(str);
221:       } catch (std::out_of_range &e) {
222:         throw Exception(ExceptionType::OUT_OF_RANGE, "Numeric value out of range.");
223:       }
224:       if (bigint > BUSTUB_INT64_MAX || bigint < BUSTUB_INT64_MIN) {
225:         throw Exception(ExceptionType::OUT_OF_RANGE, "Numeric value out of range.");
226:       }
227:       return {type_id, bigint};
228:     }
229:     case TypeId::DECIMAL: {
230:       str = value.ToString();
231:       double res = 0;
232:       try {
233:         res = stod(str);
234:       } catch (std::out_of_range &e) {
235:         throw Exception(ExceptionType::OUT_OF_RANGE, "Numeric value out of range.");
236:       }
237:       if (res > BUSTUB_DECIMAL_MAX || res < BUSTUB_DECIMAL_MIN) {
238:         throw Exception(ExceptionType::OUT_OF_RANGE, "Numeric value out of range.");
239:       }
240:       return {type_id, res};
241:     }
242:     case TypeId::VARCHAR:
243:       return value.Copy();
244:     default:
245:       break;
246:   }
247:   throw Exception("VARCHAR is not coercable to " + TypeIdToString(type_id));
248: }
249: }  // namespace bustub
