226:         manage_data_ = manage_data;
227:         if (manage_data_) {
228:           assert(len < BUSTUB_VARCHAR_MAX_LEN);
229:           value_.varlen_ = new char[len];
230:           assert(value_.varlen_ != nullptr);
231:           size_.len_ = len;
232:           memcpy(value_.varlen_, data, len);
233:         } else {
234:           // FUCK YOU GCC I do what I want.
235:           value_.const_varlen_ = data;
236:           size_.len_ = len;
237:         }
238:       }
239:       break;
240:     default:
241:       throw Exception(ExceptionType::INCOMPATIBLE_TYPE, "Invalid Type  for variable-length Value constructor");
242:   }
243: }
244: 
245: Value::Value(TypeId type, const std::string &data) : Value(type) {
246:   switch (type) {
247:     case TypeId::VARCHAR: {
248:       manage_data_ = true;
249:       // TODO(TAs): How to represent a null string here?
250:       uint32_t len = static_cast<uint32_t>(data.length()) + 1;
251:       value_.varlen_ = new char[len];
252:       assert(value_.varlen_ != nullptr);
253:       size_.len_ = len;
254:       memcpy(value_.varlen_, data.c_str(), len);
255:       break;
256:     }
257:     default:
258:       throw Exception(ExceptionType::INCOMPATIBLE_TYPE, "Invalid Type  for variable-length Value constructor");
259:   }
260: }
261: 
262: Value::Value(TypeId type, const std::vector<double> &data) : Value(type) {
263:   switch (type) {
264:     case TypeId::VECTOR: {
265:       manage_data_ = true;
266:       auto len = data.size() * sizeof(double);
267:       value_.varlen_ = new char[len];
268:       assert(value_.varlen_ != nullptr);
269:       size_.len_ = len;
270:       memcpy(value_.varlen_, data.data(), len);
271:       break;
272:     }
273:     default:
274:       throw Exception(ExceptionType::INCOMPATIBLE_TYPE, "Invalid Type  for variable-length Value constructor");
275:   }
276: }
277: 
278: // delete allocated char array space
279: Value::~Value() {
280:   switch (type_id_) {
281:     case TypeId::VARCHAR:
282:     case TypeId::VECTOR:
283:       if (manage_data_) {
284:         delete[] value_.varlen_;
285:       }
286:       break;
287:     default:
288:       break;
289:   }
290: }
291: 
292: auto Value::CheckComparable(const Value &o) const -> bool {
293:   switch (GetTypeId()) {
294:     case TypeId::BOOLEAN:
295:       return (o.GetTypeId() == TypeId::BOOLEAN || o.GetTypeId() == TypeId::VARCHAR);
296:     case TypeId::TINYINT:
297:     case TypeId::SMALLINT:
298:     case TypeId::INTEGER:
299:     case TypeId::BIGINT:
300:     case TypeId::DECIMAL:
301:       switch (o.GetTypeId()) {
302:         case TypeId::TINYINT:
303:         case TypeId::SMALLINT:
304:         case TypeId::INTEGER:
305:         case TypeId::BIGINT:
306:         case TypeId::DECIMAL:
307:         case TypeId::VARCHAR:
308:           return true;
309:         default:
310:           break;
311:       }  // SWITCH
312:       break;
313:     case TypeId::VARCHAR:
314:       // Anything can be cast to a string!
315:       return true;
316:       break;
317:     default:
318:       break;
319:   }  // END OF SWITCH
320:   return false;
321: }
322: 
323: auto Value::CheckInteger() const -> bool {
324:   switch (GetTypeId()) {
325:     case TypeId::TINYINT:
326:     case TypeId::SMALLINT:
327:     case TypeId::INTEGER:
328:     case TypeId::BIGINT:
329:       return true;
330:     default:
331:       break;
332:   }
333:   return false;
334: }
335: 
336: auto Value::GetColumn() const -> Column {
337:   switch (GetTypeId()) {
338:     case TypeId::VARCHAR:
339:     case TypeId::VECTOR: {
340:       return Column{"<val>", GetTypeId(), GetStorageSize()};
341:     }
342:     default:
343:       return Column{"<val>", GetTypeId()};
344:   }
345: }
