13: #pragma once
14: 
15: #include <cstdint>
16: #include <string>
17: 
18: #include "type/type_id.h"
19: 
20: namespace bustub {
21: 
22: class Value;
23: 
24: enum class CmpBool { CmpFalse = 0, CmpTrue = 1, CmpNull = 2 };
25: 
26: class Type {
27:  public:
28:   explicit Type(TypeId type_id) : type_id_(type_id) {}
29: 
30:   virtual ~Type() = default;
31: 
32:   // Get the size of this data type in bytes
33:   static auto GetTypeSize(TypeId type_id) -> uint64_t;
34: 
35:   // Is this type coercable from the other type
36:   auto IsCoercableFrom(TypeId type_id) const -> bool;
37: 
38:   // Debug info
39:   static auto TypeIdToString(TypeId type_id) -> std::string;
40: 
41:   static auto GetMinValue(TypeId type_id) -> Value;
42:   static auto GetMaxValue(TypeId type_id) -> Value;
43: 
44:   inline static auto GetInstance(TypeId type_id) -> Type * { return k_types[type_id]; }
45: 
46:   inline auto GetTypeId() const -> TypeId { return type_id_; }
47: 
48:   // Comparison functions
49:   //
50:   // NOTE:
51:   // We could get away with only CompareLessThan() being purely virtual, since
52:   // the remaining comparison functions can derive their logic from
53:   // CompareLessThan(). For example:
54:   //
55:   //    CompareEquals(o) = !CompareLessThan(o) && !o.CompareLessThan(this)
56:   //    CompareNotEquals(o) = !CompareEquals(o)
57:   //    CompareLessThanEquals(o) = CompareLessThan(o) || CompareEquals(o)
58:   //    CompareGreaterThan(o) = !CompareLessThanEquals(o)
59:   //    ... etc. ...
60:   //
61:   // We don't do this for two reasons:
62:   // (1) The redundant calls to CompareLessThan() may be a performance problem,
63:   //     and since Value is a core component of the execution engine, we want to
64:   //     make it as performant as possible.
65:   // (2) Keep the interface consistent by making all functions purely virtual.
66:   virtual auto CompareEquals(const Value &left, const Value &right) const -> CmpBool;
67:   virtual auto CompareNotEquals(const Value &left, const Value &right) const -> CmpBool;
68:   virtual auto CompareLessThan(const Value &left, const Value &right) const -> CmpBool;
69:   virtual auto CompareLessThanEquals(const Value &left, const Value &right) const -> CmpBool;
70:   virtual auto CompareGreaterThan(const Value &left, const Value &right) const -> CmpBool;
71:   virtual auto CompareGreaterThanEquals(const Value &left, const Value &right) const -> CmpBool;
72: 
73:   // Other mathematical functions
74:   virtual auto Add(const Value &left, const Value &right) const -> Value;
75:   virtual auto Subtract(const Value &left, const Value &right) const -> Value;
76:   virtual auto Multiply(const Value &left, const Value &right) const -> Value;
77:   virtual auto Divide(const Value &left, const Value &right) const -> Value;
78:   virtual auto Modulo(const Value &left, const Value &right) const -> Value;
79:   virtual auto Min(const Value &left, const Value &right) const -> Value;
80:   virtual auto Max(const Value &left, const Value &right) const -> Value;
81:   virtual auto Sqrt(const Value &val) const -> Value;
82:   virtual auto OperateNull(const Value &val, const Value &right) const -> Value;
83:   virtual auto IsZero(const Value &val) const -> bool;
84: 
85:   // Is the data inlined into this classes storage space, or must it be accessed
86:   // through an indirection/pointer?
87:   virtual auto IsInlined(const Value &val) const -> bool;
88: 
89:   // Return a stringified version of this value
90:   virtual auto ToString(const Value &val) const -> std::string;
91: 
92:   // Serialize this value into the given storage space.
93:   virtual void SerializeTo(const Value &val, char *storage) const;
94: 
95:   // Deserialize a value of the given type from the given storage space.
96:   virtual auto DeserializeFrom(const char *storage) const -> Value;
97: 
98:   // Create a copy of this value
99:   virtual auto Copy(const Value &val) const -> Value;
100: 
101:   virtual auto CastAs(const Value &val, TypeId type_id) const -> Value;
102: 
103:   // Access the raw varlen data stored from the tuple storage
104:   virtual auto GetData(const Value &val) const -> const char *;
105: 
106:   // Get the storage size of the value.
107:   virtual auto GetStorageSize(const Value &val) const -> uint32_t;
108: 
109:  protected:
110:   // The actual type ID
111:   TypeId type_id_;
112:   // Singleton instances.
113:   static Type *k_types[10];
114: };
115: }  // namespace bustub
