15: #include <atomic>
16: #include <cstdio>
17: #include <cstdlib>
18: #include <iostream>
19: #include <memory>
20: #include <stdexcept>
21: #include <string>
22: 
23: #include "type/type.h"
24: 
25: namespace bustub {
26: 
27: // TODO(WAN): the comment I added below is a lie, but you shouldn't need to poke around here. Don't worry about it.
28: //  Most of the exception types are type subsystem madness. I think we can get rid of it at some point.
29: /** ExceptionType is all the types of exceptions that we expect to throw in our system. */
30: enum class ExceptionType {
31:   /** Invalid exception type.*/
32:   INVALID = 0,
33:   /** Value out of range. */
34:   OUT_OF_RANGE = 1,
35:   /** Conversion/casting error. */
36:   CONVERSION = 2,
37:   /** Unknown type in the type subsystem. */
38:   UNKNOWN_TYPE = 3,
39:   /** Decimal-related errors. */
40:   DECIMAL = 4,
41:   /** Type mismatch. */
42:   MISMATCH_TYPE = 5,
43:   /** Division by 0. */
44:   DIVIDE_BY_ZERO = 6,
45:   /** Incompatible type. */
46:   INCOMPATIBLE_TYPE = 8,
47:   /** Out of memory error */
48:   OUT_OF_MEMORY = 9,
49:   /** Method not implemented. */
50:   NOT_IMPLEMENTED = 11,
51:   /** Execution exception. */
52:   EXECUTION = 12,
53: };
54: 
55: extern std::atomic<bool> global_disable_execution_exception_print;
56: 
57: class Exception : public std::runtime_error {
58:  public:
59:   /**
60:    * Construct a new Exception instance.
61:    * @param message The exception message
62:    */
63:   explicit Exception(const std::string &message, bool print = true)
64:       : std::runtime_error(message), type_(ExceptionType::INVALID) {
65: #ifndef NDEBUG
66:     if (print) {
67:       std::string exception_message = "Message :: " + message + "\n";
68:       std::cerr << exception_message;
69:     }
70: #endif
71:   }
72: 
73:   /**
74:    * Construct a new Exception instance with specified type.
75:    * @param exception_type The exception type
76:    * @param message The exception message
77:    */
78:   Exception(ExceptionType exception_type, const std::string &message, bool print = true)
79:       : std::runtime_error(message), type_(exception_type) {
80: #ifndef NDEBUG
81:     if (print && !global_disable_execution_exception_print.load()) {
82:       std::string exception_message =
83:           "\nException Type :: " + ExceptionTypeToString(type_) + ", Message :: " + message + "\n\n";
84:       std::cerr << exception_message;
85:     }
86: #endif
87:   }
88: 
89:   /** @return The type of the exception */
90:   auto GetType() const -> ExceptionType { return type_; }
91: 
92:   /** @return A human-readable string for the specified exception type */
93:   static auto ExceptionTypeToString(ExceptionType type) -> std::string {
94:     switch (type) {
95:       case ExceptionType::INVALID:
96:         return "Invalid";
97:       case ExceptionType::OUT_OF_RANGE:
98:         return "Out of Range";
99:       case ExceptionType::CONVERSION:
100:         return "Conversion";
101:       case ExceptionType::UNKNOWN_TYPE:
102:         return "Unknown Type";
103:       case ExceptionType::DECIMAL:
104:         return "Decimal";
105:       case ExceptionType::MISMATCH_TYPE:
106:         return "Mismatch Type";
107:       case ExceptionType::DIVIDE_BY_ZERO:
108:         return "Divide by Zero";
109:       case ExceptionType::INCOMPATIBLE_TYPE:
110:         return "Incompatible type";
