#pragma once

#include <cstdio>
#include <cstring>
#include <functional>
#include <sstream>
#include <string>
#include <vector>

#ifndef GTEST_API_
#define GTEST_API_
#endif

namespace testing {

inline bool &ShouldRunDisabledTests() {
  static bool value = false;
  return value;
}
inline bool &ShouldListTests() {
  static bool value = false;
  return value;
}

struct TestInfo {
  std::string suite_name;
  std::string test_name;
  std::function<void()> body;
};

inline std::vector<TestInfo> &GetTestRegistry() {
  static std::vector<TestInfo> registry;
  return registry;
}

struct Registrar {
  Registrar(const char *suite, const char *name, std::function<void()> body) {
    GetTestRegistry().push_back({suite, name, body});
  }
};

class AssertionException {
 public:
  explicit AssertionException(const std::string &msg) : message_(msg) {}
  const std::string &message() const { return message_; }

 private:
  std::string message_;
};

inline void InitGoogleTest(int *argc, char **argv) {
  if (argc == nullptr || argv == nullptr) return;
  for (int i = 1; i < *argc; i++) {
    if (std::strncmp(argv[i], "--gtest_also_run_disabled_tests", 31) == 0) {
      ShouldRunDisabledTests() = true;
    }
    if (std::strncmp(argv[i], "--gtest_list_tests", 18) == 0) {
      ShouldListTests() = true;
    }
  }
}

inline void InitGoogleTest() {}

inline int RUN_ALL_TESTS() {
  // Handle --gtest_list_tests
  if (ShouldListTests()) {
    std::string cur_suite;
    for (auto &test : GetTestRegistry()) {
      if (test.suite_name != cur_suite) {
        cur_suite = test.suite_name;
        printf("%s.\n", cur_suite.c_str());
      }
      printf("  %s\n", test.test_name.c_str());
    }
    return 0;
  }

  int passed = 0, failed = 0, skipped = 0;
  for (auto &test : GetTestRegistry()) {
    bool disabled = (test.test_name.rfind("DISABLED_", 0) == 0);
    if (disabled && !ShouldRunDisabledTests()) {
      ++skipped;
      continue;
    }
    printf("[ RUN      ] %s.%s\n", test.suite_name.c_str(), test.test_name.c_str());
    try {
      test.body();
      printf("[       OK ] %s.%s\n", test.suite_name.c_str(), test.test_name.c_str());
      ++passed;
    } catch (const AssertionException &e) {
      printf("%s\n", e.message().c_str());
      printf("[  FAILED  ] %s.%s\n", test.suite_name.c_str(), test.test_name.c_str());
      ++failed;
    } catch (const std::exception &e) {
      printf("Exception: %s\n", e.what());
      printf("[  FAILED  ] %s.%s\n", test.suite_name.c_str(), test.test_name.c_str());
      ++failed;
    } catch (...) {
      printf("Unknown exception\n");
      printf("[  FAILED  ] %s.%s\n", test.suite_name.c_str(), test.test_name.c_str());
      ++failed;
    }
  }
  printf("\n[==========] %d tests ran.\n", passed + failed);
  printf("[  PASSED  ] %d tests.\n", passed);
  if (failed > 0) printf("[  FAILED  ] %d tests.\n", failed);
  if (skipped > 0) printf("[  SKIPPED ] %d tests.\n", skipped);
  return (failed > 0) ? 1 : 0;
}

}  // namespace testing

#define TEST(suite, name)                                                  \
  static void GTEST_IMPL_##suite##_##name##_Body_();                      \
  static ::testing::Registrar GTEST_REG_##suite##_##name(                 \
      #suite, #name, GTEST_IMPL_##suite##_##name##_Body_);                \
  static void GTEST_IMPL_##suite##_##name##_Body_()

template <typename T1, typename T2>
inline void GtestAssertEq_(const T1 &v1, const T2 &v2, const char *expr1,
                            const char *expr2, const char *file, int line) {
  if (!(v1 == v2)) {
    std::ostringstream oss;
    oss << file << ":" << line << ": Failure\n"
        << "Expected equality of these values:\n"
        << "  " << expr1 << "\n"
        << "    Which is: " << v1 << "\n"
        << "  " << expr2 << "\n"
        << "    Which is: " << v2;
    throw ::testing::AssertionException(oss.str());
  }
}

#define ASSERT_EQ(val1, val2) GtestAssertEq_(val1, val2, #val1, #val2, __FILE__, __LINE__)
#define EXPECT_EQ(val1, val2) GtestAssertEq_(val1, val2, #val1, #val2, __FILE__, __LINE__)

#define ASSERT_NE(val1, val2)                                              \
  do {                                                                     \
    if ((val1) == (val2)) {                                                \
      std::ostringstream __oss;                                            \
      __oss << __FILE__ << ":" << __LINE__ << ": " #val1 " != " #val2;    \
      throw ::testing::AssertionException(__oss.str());                    \
    }                                                                      \
  } while (0)

#define ASSERT_TRUE(cond)                                                  \
  do {                                                                     \
    if (!(cond)) {                                                         \
      std::ostringstream __oss;                                            \
      __oss << __FILE__ << ":" << __LINE__ << ": " #cond " is not true";  \
      throw ::testing::AssertionException(__oss.str());                    \
    }                                                                      \
  } while (0)

#define ASSERT_FALSE(cond) ASSERT_TRUE(!(cond))
#define EXPECT_TRUE(cond) ASSERT_TRUE(cond)
#define EXPECT_FALSE(cond) ASSERT_FALSE(cond)
#define ASSERT_LT(v1, v2) ASSERT_TRUE((v1) < (v2))
#define ASSERT_GT(v1, v2) ASSERT_TRUE((v1) > (v2))
#define ASSERT_LE(v1, v2) ASSERT_TRUE((v1) <= (v2))
#define ASSERT_GE(v1, v2) ASSERT_TRUE((v1) >= (v2))

