#include "primer/hyperloglog.h"

#include <algorithm>
#include <cmath>
#include <mutex>  // NOLINT

namespace bustub {

template <typename KeyType>
HyperLogLog<KeyType>::HyperLogLog(int16_t n_bits) : cardinality_(0), n_bits_(n_bits) {
  if (n_bits_ < 0) {
    // Invalid: keep m_=0, registers_ empty, cardinality always 0
    m_ = 0;
  } else {
    m_ = static_cast<int64_t>(1) << n_bits_;
    registers_.resize(m_, 0);
  }
}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeBinary(const hash_t &hash) const -> std::bitset<BITSET_CAPACITY> {
  return std::bitset<BITSET_CAPACITY>(hash);
}

template <typename KeyType>
auto HyperLogLog<KeyType>::PositionOfLeftmostOne(const std::bitset<BITSET_CAPACITY> &bset) const -> uint64_t {
  // Count leading zeros from bit 63 (MSB) downward, return count + 1
  // For all-zero bitset: return 65
  for (int i = BITSET_CAPACITY - 1; i >= 0; i--) {
    if (bset[i]) {
      // Leading zeros = (BITSET_CAPACITY - 1 - i)
      return static_cast<uint64_t>(BITSET_CAPACITY - 1 - i) + 1;
    }
  }
  // All zeros: position is 65
  return BITSET_CAPACITY + 1;
}

template <typename KeyType>
auto HyperLogLog<KeyType>::AddElem(KeyType val) -> void {
  if (n_bits_ < 0) return;

  hash_t hash = CalculateHash(val);

  // Determine register index j and value portion
  uint64_t j = 0;
  uint64_t value = hash;
  if (n_bits_ > 0) {
    j = hash >> (static_cast<uint64_t>(64) - static_cast<uint64_t>(n_bits_));
    value = hash << static_cast<uint64_t>(n_bits_);
  }
  // For n_bits_==0: j=0, value=hash (no shift needed)

  auto bset = ComputeBinary(value);
  uint64_t pos = PositionOfLeftmostOne(bset);

  std::lock_guard<std::mutex> lock(mutex_);
  registers_[j] = std::max(registers_[j], pos);
}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeCardinality() -> void {
  if (n_bits_ < 0 || m_ == 0) {
    cardinality_ = 0;
    return;
  }

  // E = CONSTANT * m^2 / sum(2^{-M[j]})
  double sum = 0.0;
  for (int64_t j = 0; j < m_; j++) {
    sum += std::pow(2.0, -static_cast<double>(registers_[j]));
  }

  double estimate = CONSTANT * static_cast<double>(m_) * static_cast<double>(m_) / sum;
  cardinality_ = static_cast<size_t>(std::floor(estimate));
}

template class HyperLogLog<int64_t>;
template class HyperLogLog<std::string>;

}  // namespace bustub

