  ASSERT_EQ(ans, 3);

  auto expected2 = obj.GetDenseBucket();
  ASSERT_EQ(15UL, expected2[0].to_ulong());
  ASSERT_EQ(3, obj.GetOverflowBucketofIndex(0).to_ullong());

